import re, json, csv
from pathlib import Path
from collections import defaultdict, deque

base = Path('/app')

def parse_day_from_name(name):
    m = re.search(r'day_(\d+)_', name)
    if not m:
        raise ValueError(name)
    return int(m.group(1))

def parse_id_from_name(name, prefix):
    m = re.search(fr'_{prefix}_(\d+)', name)
    if not m:
        raise ValueError(name)
    return f'{prefix}_{int(m.group(1))}'

# Parse supplier receipts
supplier = []
for path in sorted((base/'raw_supplier_receipts').iterdir()):
    day = parse_day_from_name(path.name)
    producer = re.search(r'PR_\d+', path.name).group(0)
    if path.suffix == '.json':
        data = json.loads(path.read_text())
        for item in data['items']:
            supplier.append((day, producer, item['prod_id'], int(item['delivered_qty'])))
    elif path.suffix == '.csv':
        with path.open() as f:
            reader = csv.DictReader(f, delimiter=';')
            for row in reader:
                supplier.append((day, producer, row['PRODUCT'], int(row['DELIVERED_QTY'])))
    else:
        text = path.read_text().strip().splitlines()
        if 'key-value' in path.name:
            for line in text:
                if line.startswith('PRODUCT:'):
                    m = re.search(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)', line)
                    supplier.append((day, producer, m.group(1), int(m.group(2))))
        else:
            for line in text:
                m = re.search(r'delivered (\d+) units of product (P_\d+)', line)
                supplier.append((day, producer, m.group(2), int(m.group(1))))

# Parse wholesaler receipts
sup_seq = {}
for path in (base/'raw_wholesaler_receipts').iterdir():
    text = path.read_text().splitlines()
    day = int(text[0].split(':')[1].strip())
    pr = text[1].split(':')[1].strip()
    seq = int(text[2].split(':')[1].strip())
    sup_seq[(day, pr)] = seq

# group supplier deliveries by day/product sorted by supplier seq
by_day_prod = defaultdict(list)
for day, pr, prod, qty in supplier:
    by_day_prod[(day, prod)].append((sup_seq[(day, pr)], pr, qty))
for k in by_day_prod:
    by_day_prod[k].sort()

# Parse raw orders
orders = defaultdict(dict)
for path in (base/'raw_orders').iterdir():
    day = parse_day_from_name(path.name)
    store = re.search(r'S_\d+', path.name).group(0)
    if path.suffix == '.json':
        data = json.loads(path.read_text())
        for item in data['items']:
            orders[(day, store)][item['product_id']] = int(item['quantity'])
    elif path.suffix == '.csv':
        with path.open() as f:
            reader = csv.DictReader(f, delimiter=';')
            for row in reader:
                orders[(day, store)][row['PRODUCT']] = int(row['QUANTITY'])
    else:
        lines = path.read_text().strip().splitlines()
        if 'key-value' in path.name:
            for line in lines:
                m = re.search(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)', line)
                orders[(day, store)][m.group(1)] = int(m.group(2))
        else:
            for line in lines:
                m = re.search(r'deliver (\d+) units of product (P_\d+)', line)
                orders[(day, store)][m.group(2)] = int(m.group(1))

# Parse store receipts
store_seq = {}
store_total = {}
for path in (base/'raw_wholesaler_store_receipts').iterdir():
    text = path.read_text().splitlines()
    day = int(text[0].split(':')[1].strip())
    store = text[1].split(':')[1].strip()
    seq = int(text[2].split(':')[1].strip())
    total = int(text[3].split(':')[1].strip())
    store_seq[(day, store)] = seq
    store_total[(day, store)] = total

stores = sorted({s for _,s in store_seq})
products = sorted({p for _,_,p,_ in supplier}, key=lambda x:int(x.split('_')[1]))

# Simulate wholesaler inventory if all supplier receipts first, then stores.
inv = {p: deque() for p in products}
max_mismatch = []
for day in range(1, 366):
    for p in products:
        for seq, pr, qty in by_day_prod.get((day,p),[]):
            inv[p].append([pr, qty])
    # deliver to stores in store seq order
    for store in sorted(stores, key=lambda s: store_seq[(day,s)]):
        delivered_total = 0
        for p, qty in orders.get((day, store), {}).items():
            want = qty
            q = inv[p]
            while want and q:
                take = min(want, q[0][1])
                want -= take
                q[0][1] -= take
                delivered_total += take
                if q[0][1]==0:
                    q.popleft()
        exp = store_total[(day, store)]
        if delivered_total != exp:
            max_mismatch.append((day, store, delivered_total, exp))
            if len(max_mismatch) >= 10:
                break
    if len(max_mismatch) >= 10:
        break

print('mismatches', len(max_mismatch))
print(max_mismatch[:10])
