    elif path.suffix == '.csv':
        with path.open() as f:
            reader = csv.DictReader(f, delimiter=';')
            for row in reader:
                order_rows.append((day, store, row['PRODUCT'], int(row['QUANTITY'])))
    else:
        lines = path.read_text().strip().splitlines()
        if 'key-value' in path.name:
            for line in lines:
                m = re.search(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)', line)
                order_rows.append((day, store, m.group(1), int(m.group(2))))
        else:
            for line in lines:
                m = re.search(r'deliver (\d+) units of product (P_\d+)', line)
                order_rows.append((day, store, m.group(2), int(m.group(1))))
orders_df = pd.DataFrame(order_rows, columns=['day','store','product','qty'])

# Parse store receipts
store_rows = []
for path in (base/'raw_wholesaler_store_receipts').iterdir():
    lines = path.read_text().splitlines()
    store_rows.append((int(lines[0].split(':')[1]), lines[1].split(':')[1].strip(), int(lines[2].split(':')[1]), int(lines[3].split(':')[1])))
store_receipts_df = pd.DataFrame(store_rows, columns=['day','store','store_seq','total_delivered'])

# Sales aggregate
sales_df = pd.read_csv(base/'sales_log.csv')
sales_agg = sales_df.groupby(['Day','Store_ID','Product_ID'], as_index=False)[['Reported_Demand','Sold_Quantity','Lost_Sales']].sum()
sales_agg.columns = ['day','store','product','demand','sold','lost']

products = sorted(supplier_df['product'].unique(), key=lambda x:int(x.split('_')[1]))
stores = sorted(store_receipts_df['store'].unique(), key=lambda x:int(x.split('_')[1]))

supplier_by_day_prod = defaultdict(list)
for row in supplier_df.sort_values(['day','product','supplier_seq','producer']).itertuples(index=False):
    supplier_by_day_prod[(row.day,row.product)].append((int(row.supplier_seq), row.producer, int(row.qty)))

orders_by_day_store = defaultdict(list)
for row in orders_df.itertuples(index=False):
    orders_by_day_store[(int(row.day), row.store)].append((row.product, int(row.qty)))

store_seq = {(int(r.day), r.store): int(r.store_seq) for r in store_receipts_df.itertuples(index=False)}
store_total = {(int(r.day), r.store): int(r.total_delivered) for r in store_receipts_df.itertuples(index=False)}

# simulate wholesaler -> store deliveries with producer segments
wh_inv = {p: deque() for p in products}
delivery_rows = []
delivery_segment_rows = []
for day in range(1, 366):
    for p in products:
        for seq, pr, qty in supplier_by_day_prod.get((day,p),[]):
            wh_inv[p].append([pr, qty])
    for store in sorted(stores, key=lambda s: store_seq[(day,s)]):
        total = 0
        for p, qty in orders_by_day_store.get((day,store), []):
            want = qty
            delivered = 0
            while want and wh_inv[p]:
                take = min(want, wh_inv[p][0][1])
                want -= take
                wh_inv[p][0][1] -= take
                delivered += take
                total += take
                delivery_segment_rows.append((day, store, p, wh_inv[p][0][0], take))
                if wh_inv[p][0][1] == 0:
                    wh_inv[p].popleft()
            if delivered:
                delivery_rows.append((day, store, p, delivered))
        if total != store_total[(day,store)]:
            raise RuntimeError(('delivery mismatch', day, store, total, store_total[(day,store)]))

deliveries_df = pd.DataFrame(delivery_rows, columns=['day','store','product','delivered'])
delivery_segments_df = pd.DataFrame(delivery_segment_rows, columns=['day','store','product','producer','qty'])

# simulate store sales using previous deliveries, FIFO by producer
store_inv = {(s,p): deque() for s in stores for p in products}
sold_segment_rows = []
inv_checks = []
# index deliveries by day/store/product
for day in range(1, 366):
    # sell from inventory available at start of day (deliveries from prior days already loaded)
    day_sales = sales_agg[sales_agg['day']==day]
    for row in day_sales.itertuples(index=False):
        key = (row.store, row.product)
        q = int(row.sold)
        avail = sum(x[1] for x in store_inv[key])
        if q > avail:
            inv_checks.append((day, row.store, row.product, q, avail))
        remaining = q
        while remaining and store_inv[key]:
            take = min(remaining, store_inv[key][0][1])
            remaining -= take
            store_inv[key][0][1] -= take
            sold_segment_rows.append((day, row.store, row.product, store_inv[key][0][0], take))
            if store_inv[key][0][1] == 0:
                store_inv[key].popleft()
        if remaining:
            raise RuntimeError(('negative inventory selling', day, row.store, row.product, q, avail))
    # then append same-day deliveries for next day's sales
    for row in delivery_segments_df[delivery_segments_df['day']==day].itertuples(index=False):
        store_inv[(row.store,row.product)].append([row.producer, int(row.qty)])

sold_segments_df = pd.DataFrame(sold_segment_rows, columns=['day','store','product','producer','qty'])

# compute end inventory summary maybe not needed
pickle.dump({
    'supplier_df': supplier_df,
    'orders_df': orders_df,
    'store_receipts_df': store_receipts_df,
    'sales_agg': sales_agg,
    'deliveries_df': deliveries_df,
    'delivery_segments_df': delivery_segments_df,
    'sold_segments_df': sold_segments_df,
}, out.open('wb'))
print('cached', out)
print('supplier rows', len(supplier_df), 'orders rows', len(orders_df), 'deliveries', len(deliveries_df), 'delivery segments', len(delivery_segments_df), 'sold segments', len(sold_segments_df))
